234→void FastDdsSubscriptionManager::close_subscription(const std::string& topic_name, SubscriptionInfo& info) {
235→  try {
236→    info.reader->set_listener(nullptr);
237→    info.subscriber->delete_datareader(info.reader);
238→    info.participant->delete_subscriber(info.subscriber);
239→    info.participant->delete_topic(info.topic);
240→  } catch (const std::exception& e) {
241→    spdlog::warn("Error cleaning up reader for '{}': {}", topic_name, e.what());
242→  } catch (...) {
243→    spdlog::warn("Unknown error cleaning up reader for '{}'", topic_name);
244→  }
245→}
